func windowsProcessAlive(pid int) bool {
	return isPIDAlive(pid)
}

func signalWindowsProcessOnce(pid int, sig os.Signal) bool {
	if pid <= 0 {
		return false
	}
	p, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	_ = p.Signal(sig)
	return true
}

func killWindowsProcessOnce(pid int) bool {
	if pid <= 0 {
		return false
	}
	p, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	_ = p.Kill()
	return true
}

