// StartManagedExecuteLoop starts a server-managed work worker in a separate
// process group. The launched process runs `ddx work --server-managed <id>`
// and the parent keeps the worker registry record in sync with the child
// process identity.
func (m *WorkerManager) StartManagedExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}
	spec.ProjectRoot = effectiveRoot
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return WorkerRecord{}, err
	}

	// Keep the same preflight contract as the in-process path so invalid
	// harness/model combinations fail before a record is surfaced.
	if !spec.OpaquePassthrough {
		if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider); err != nil {
			return WorkerRecord{}, fmt.Errorf("work: %w", err)
		}
	}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	specData, _ := json.MarshalIndent(spec, "", "  ")
	if err := os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644); err != nil {
		return WorkerRecord{}, err
	}

	record := WorkerRecord{
		ID:           id,
		Kind:         "work",
		State:        "running",
		Status:       "running",
		ProjectRoot:  effectiveRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		Profile:      agent.NormalizeRoutingProfile(spec.Profile),
		Effort:       spec.Effort,
		Once:         executeLoopOnce(spec),
		PollInterval: executeLoopPollInterval(spec).String(),
		StdoutPath:   relToProject(m.projectRoot, filepath.Join(dir, "worker.log")),
		SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
		StartedAt:    time.Now().UTC(),
	}
	record.Lifecycle = append(record.Lifecycle, WorkerLifecycleEvent{
		Action:    "start",
		Actor:     "local-operator",
		Timestamp: record.StartedAt,
		Detail:    lifecycleStartDetail(spec),
	})
	if err := m.writeRecord(dir, record); err != nil {
		return WorkerRecord{}, err
	}

	ctx, cancel := context.WithCancel(context.Background())
	logBuf := &bytes.Buffer{}
	progressCh := make(chan agent.ProgressEvent, 64)
	handle := &workerHandle{
		record:       record,
		cancel:       cancel,
		logBuf:       logBuf,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  record.StartedAt,
	}

	m.mu.Lock()
	m.workers[id] = handle
	m.mu.Unlock()

	m.ensureWatchdog()
	go m.drainProgress(id, handle, progressCh)

	binary, err := m.resolveManagedWorkerBinaryPath()
	if err != nil {
		m.failManagedLaunch(id, dir, handle, progressCh, err)
		return WorkerRecord{}, err
	}

	cmd := exec.Command(binary, "work", "--server-managed", id, "--project", effectiveRoot)
	cmd.Dir = effectiveRoot
	configureManagedWorkerProcess(cmd)
	cmd.Stdout = io.Discard
	cmd.Stderr = io.Discard
	if err := cmd.Start(); err != nil {
		m.failManagedLaunch(id, dir, handle, progressCh, err)
		return WorkerRecord{}, err
	}

	record.PID = cmd.Process.Pid
	record.PGID = cmd.Process.Pid
	if len(record.Lifecycle) > 0 {
		record.Lifecycle[0].Detail = strings.TrimSpace(fmt.Sprintf("%s pid=%d pgid=%d", record.Lifecycle[0].Detail, record.PID, record.PGID))
	}
	_ = m.writeRecord(dir, record)

	m.mu.Lock()
	handle.record = record
	m.mu.Unlock()

	go m.waitManagedWorkerExit(id, dir, handle, progressCh, cmd)
	return record, nil
}

func (m *WorkerManager) failManagedLaunch(id, dir string, handle *workerHandle, progressCh chan agent.ProgressEvent, err error) {
	now := time.Now().UTC()
	m.mu.Lock()
	if h, ok := m.workers[id]; ok && h == handle {
		handle.record.State = "failed"
		handle.record.Status = "failed"
		handle.record.Error = err.Error()
		handle.record.LastError = err.Error()
		handle.record.FinishedAt = now
		snapshot := handle.record
		m.mu.Unlock()
		_ = m.writeRecord(dir, snapshot)
	} else {
		m.mu.Unlock()
	}
	close(progressCh)
	<-handle.progressDone
	m.mu.Lock()
	delete(m.workers, id)
	m.mu.Unlock()
}

func (m *WorkerManager) waitManagedWorkerExit(id, dir string, handle *workerHandle, progressCh chan agent.ProgressEvent, cmd *exec.Cmd) {
	exitErr := cmd.Wait()
	finalRecord, readErr := m.readRecord(dir)
	if readErr != nil {
		finalRecord = handle.record
	}
	now := time.Now().UTC()

	m.mu.Lock()
	if finalRecord.ID == "" {
		finalRecord = handle.record
	}
	if handle.record.State == "stopped" || handle.record.State == "reaped" {
		finalRecord.State = handle.record.State
		finalRecord.Status = handle.record.State
	} else if finalRecord.State == "running" {
		if exitErr != nil {
			finalRecord.State = "failed"
			finalRecord.Status = "failed"
			finalRecord.Error = exitErr.Error()
			finalRecord.LastError = exitErr.Error()
		} else {
			finalRecord.State = "exited"
			if finalRecord.Status == "" || finalRecord.Status == "running" {
				finalRecord.Status = "exited"
			}
		}
	}
	if finalRecord.PID == 0 {
		finalRecord.PID = handle.record.PID
	}
	if finalRecord.PGID == 0 {
		finalRecord.PGID = handle.record.PGID
	}
	if finalRecord.FinishedAt.IsZero() {
		finalRecord.FinishedAt = now
	}
	handle.record = finalRecord
	m.mu.Unlock()

	_ = m.writeRecord(dir, finalRecord)
	close(progressCh)
}

func (m *WorkerManager) resolveManagedWorkerBinaryPath() (string, error) {
	if m != nil && m.managedWorkerBinaryPath != nil {
		if path := strings.TrimSpace(m.managedWorkerBinaryPath()); path != "" {
			return path, nil
		}
	}

	if path, err := exec.LookPath("ddx"); err == nil {
		return path, nil
	}
	if exe, err := os.Executable(); err == nil && filepath.Base(exe) == "ddx" {
		return exe, nil
	}
	return "", fmt.Errorf("ddx managed worker binary not found; install ddx or override WorkerManager.managedWorkerBinaryPath")
}

// RunServerManagedExecuteLoop runs an already-launched server-managed worker
// inside the worker process itself. The parent process creates the record and
// process group; the child only needs to attach to the existing worker id.
func RunServerManagedExecuteLoop(ctx context.Context, projectRoot, workerID string) error {
	m := NewWorkerManager(projectRoot)
	return m.runServerManagedExecuteLoop(ctx, workerID)
}

func (m *WorkerManager) runServerManagedExecuteLoop(ctx context.Context, workerID string) error {
	dir := filepath.Join(m.rootDir, workerID)
	rec, err := m.readRecord(dir)
	if err != nil {
		return err
	}

	specPath := filepath.Join(dir, "spec.json")
	specData, err := os.ReadFile(specPath)
	if err != nil {
		return err
	}
	var spec ExecuteLoopWorkerSpec
	if err := json.Unmarshal(specData, &spec); err != nil {
		return err
	}
	if spec.ProjectRoot == "" {
		spec.ProjectRoot = rec.ProjectRoot
	}
	if spec.ProjectRoot == "" {
		spec.ProjectRoot = m.projectRoot
	}
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return err
	}

	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return err
	}
	defer logFile.Close() //nolint:errcheck

	eventsPath := filepath.Join(dir, "worker-events.jsonl")

	eventsPath := filepath.Join(dir, "worker-events.jsonl")
	eventsFile, err := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return err
	}

	logBuf := &bytes.Buffer{}
	multiLog := io.MultiWriter(logBuf, logFile)
	progressCh := make(chan agent.ProgressEvent, 64)
	handle := &workerHandle{
		record:       rec,
		cancel:       func() {},
		logBuf:       logBuf,
		logFile:      logFile,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  time.Now().UTC(),
	}
	m.ensureWatchdog()
	go m.drainProgress(workerID, handle, progressCh)

	m.runWorker(ctx, workerID, dir, spec, spec.ProjectRoot, handle, multiLog, eventsFile, progressCh)
	return nil
}

func (m *WorkerManager) startExecuteLoopForServer(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	if m != nil && m.BeadWorkerFactory != nil {
		return m.StartExecuteLoop(spec)
	}
	return m.StartManagedExecuteLoop(spec)
}

